from __future__ import annotations

import math
from dataclasses import dataclass
from enum import IntEnum
from typing import Dict, Tuple, Optional

import numpy as np
from scipy.signal import butter, sosfiltfilt, welch, coherence


# =============================================================================
# Integer classifications (enums) and flags
# =============================================================================

class ContactState(IntEnum):
    """Binary on/off skin classification."""
    OFF_SKIN = 0
    ON_SKIN = 1


class MotionGrade(IntEnum):
    """Ternary motion/noise classification for on-skin segments."""
    GOOD = 0
    MODERATE = 1
    BAD = 2


# Bitmask flags for interpretability / telemetry (combine with OR).
FLAG_CLIPPING_HIGH       = 1 << 0   # samples pinned near ADC max
FLAG_CLIPPING_LOW        = 1 << 1   # samples pinned near ADC min
FLAG_NO_CARDIAC_PEAK     = 1 << 2   # could not find/confirm cardiac band peak
FLAG_LOW_PERFUSION       = 1 << 3   # PI below floor (may still be on-skin)
FLAG_DECOUPLED_CHANNELS  = 1 << 4   # Red/IR low coupling at heart band
FLAG_R_UNSTABLE          = 1 << 5   # ratio instability across sub-slices
FLAG_AMBIENT_DOMINANT    = 1 << 6   # low out-of-band, no peak → ambient/loose
FLAG_INPUT_BAD           = 1 << 7   # NaNs, mismatched lengths, or too-short
FLAG_NUMERIC_ISSUE       = 1 << 8   # fallback due to numerical problems


# =============================================================================
# Output container (keep integers for classifications as requested)
# =============================================================================

@dataclass
class PPGQualityResult:
    # Core outputs (integers)
    contact_state: int              # ContactState.*
    motion_grade: int               # MotionGrade.*
    quality_index: int              # 0..100

    # Optional physiological & diagnostics
    hr_bpm: Optional[float]         # derived from fp (None if unknown)
    flags: int                      # bitmask (combine FLAG_*)

    # Diagnostics (handy for tuning/telemetry)
    snr_ir_db: float
    snr_red_db: float
    pi_ir_pct: float
    pi_red_pct: float
    corr_red_ir: float              # time-domain Pearson corr of bandlimited AC
    coh_fp: float                   # magnitude-squared coherence at fp
    obf: float                      # out-of-band fraction (>8 Hz)
    fp_hz: Optional[float]          # dominant frequency (Hz) if found
    std_logR: float                 # stability of R across subslices


# =============================================================================
# Utility helpers
# =============================================================================

def _safe_as_float_1d(x) -> np.ndarray:
    """Convert to 1-D float64 array, squeezing and guarding NaNs/Infs."""
    a = np.asarray(x, dtype=np.float64).squeeze()
    if a.ndim != 1:
        raise ValueError("Input must be a 1-D array.")
    # Replace Infs with NaN; then nan_to_num to zero (we will handle consequences).
    a[~np.isfinite(a)] = np.nan
    return np.nan_to_num(a, copy=False)


def _butter_bandpass_sos(f_lo: float, f_hi: float, fs: float, order: int = 4) -> np.ndarray:
    """Create stable SOS for Butterworth band-pass. f_lo < f_hi, both in Hz."""
    nyq = 0.5 * fs
    f_lo = max(1e-6, min(f_lo, nyq * 0.99))
    f_hi = max(f_lo * 1.01, min(f_hi, nyq * 0.999))
    return butter(order, [f_lo / nyq, f_hi / nyq], btype="bandpass", output="sos")


def _rms(x: np.ndarray) -> float:
    """Root-mean-square."""
    n = len(x)
    if n == 0:
        return 0.0
    return float(np.sqrt(np.sum(x * x) / n))


def _power_snr_and_peak(
    x: np.ndarray,
    fs: float,
    fmin: float,
    fmax: float,
    peak_bw: float = 0.2,
    nperseg: Optional[int] = None,
) -> Tuple[float, Optional[float], np.ndarray, np.ndarray]:
    """
    Compute Welch PSD and SNR around dominant peak in [fmin, fmax].

    Returns:
        snr_db:   10*log10(P_in_peak_band / P_outside)
        f_peak:   peak frequency in Hz within [fmin, fmax] (or None)
        f, Pxx:   Welch frequencies and PSD
    """
    if nperseg is None:
        # 1 s segments if possible; ensure at least 256 samples within constraints
        nperseg = int(max(256, min(len(x), round(fs))))
    if len(x) < 8:
        return -np.inf, None, np.array([]), np.array([])

    try:
        f, Pxx = welch(x, fs=fs, nperseg=nperseg, noverlap=nperseg // 2, window="hann", detrend="constant")
    except Exception:
        # Fallback minimal periodogram if Welch fails
        try:
            X = np.fft.rfft(x * np.hanning(len(x)))
            Pxx = (np.abs(X) ** 2) / (fs * np.sum(np.hanning(len(x)) ** 2))
            f = np.fft.rfftfreq(len(x), d=1.0 / fs)
        except Exception:
            return -np.inf, None, np.array([]), np.array([])

    sel = (f >= fmin) & (f <= fmax)
    if not np.any(sel):
        return -np.inf, None, f, Pxx

    f_sel = f[sel]
    P_sel = Pxx[sel]
    if len(P_sel) == 0 or np.all(P_sel <= 0):
        return -np.inf, None, f, Pxx

    idx_peak = int(np.argmax(P_sel))
    f_peak = float(f_sel[idx_peak])

    in_band = (f >= max(fmin, f_peak - peak_bw)) & (f <= min(fmax, f_peak + peak_bw))
    P_in = float(np.sum(Pxx[in_band]))

    # Exclude DC and the in-band region for the "noise" estimate
    exclude = in_band.copy()
    exclude[f == 0.0] = True
    P_out = float(np.sum(Pxx[~exclude]))

    if P_out <= 0.0:
        snr_db = 30.0  # essentially very high
    else:
        snr = max(P_in / P_out, 1e-12)
        snr_db = 10.0 * math.log10(snr)
    return snr_db, f_peak, f, Pxx


def _clipping_fraction(x: np.ndarray, adc_bits: Optional[int]) -> Tuple[float, float]:
    """
    Fraction of samples at/near rails.
    If adc_bits given: explicit 0 and 2^bits-1 rails (±1 LSB margin).
    Else: heuristic via 0.1% extreme bins in the histogram.
    """
    n = len(x)
    if n == 0:
        return 0.0, 0.0
    if adc_bits is not None:
        lo = 0.0
        hi = float((1 << adc_bits) - 1)
        frac_low = float(np.mean(x <= (lo + 1.0)))
        frac_high = float(np.mean(x >= (hi - 1.0)))
    else:
        # Heuristic: treat near-global min/max as rails if many samples pile there
        lo_guess = np.percentile(x, 0.1)
        hi_guess = np.percentile(x, 99.9)
        tol = max(1e-9, 1e-6 * (np.std(x) if np.std(x) > 0 else 1.0))
        frac_low = float(np.mean(np.abs(x - lo_guess) <= tol))
        frac_high = float(np.mean(np.abs(x - hi_guess) <= tol))
    return frac_low, frac_high


def _split_into_slices(a: np.ndarray, n_slices: int) -> np.ndarray:
    """Split into ~equal contiguous slices (dtype=object to allow jagged)."""
    n = len(a)
    if n_slices <= 1 or n < n_slices:
        return np.array([a], dtype=object)
    idx = np.linspace(0, n, n_slices + 1, dtype=int)
    return np.array([a[idx[i]:idx[i+1]] for i in range(n_slices)], dtype=object)


# =============================================================================
# Main API
# =============================================================================

def assess_ppg_quality(
    red: np.ndarray,
    ir: np.ndarray,
    fs_hz: float = 25,
    adc_bits: Optional[int] = 12,
    # Tunables (kept as parameters for configurability)
    f_card_min: float = 0.6,
    f_card_max: float = 3.5,
    band_lo_hz: float = 0.5,
    band_hi_hz: float = 12.0,
    snr_pass_db: float = 2.5,
    corr_pass_min: float = 0.40,
    pi_floor_pct: float = 0.07,          # non-adaptive floor; can be adapted in outer layer
    std_logR_bad: float = 0.20,
    obf_high_ref: float = 0.50,          # OBF mapped to 1.0 at this level
    return_dict: bool = False,
) -> PPGQualityResult:
    """
    Assess PPG signal quality for a *single* analysis window of Red/IR samples.

    Parameters
    ----------
    red, ir : 1-D arrays (same length)
        Windowed Red and IR samples (raw integers or floats). Arrays may contain NaNs/Infs
        (they will be coerced to zero), but sustained NaNs will degrade metrics and set flags.
    fs_hz : float
        Sampling rate (Hz).
    adc_bits : int | None
        If raw integers represent full-scale 0..(2^bits - 1), pass bits to enable explicit rail checks.
    f_card_min, f_card_max : float
        Expected cardiac frequency search band (Hz) for peak detection and SNR.
    band_lo_hz, band_hi_hz : float
        Band-pass for extracting the pulsatile AC component (Hz).
    snr_pass_db : float
        Minimal SNR (dB) in the cardiac band to consider the channel as detecting a pulse.
    corr_pass_min : float
        Minimal Red–IR correlation (band-limited AC) to accept on-skin contact.
    pi_floor_pct : float
        Minimal perfusion index (%) floor. Consider adapting this using a rolling baseline externally.
    std_logR_bad : float
        Standard deviation threshold for log(R) instability across sub-slices.
    obf_high_ref : float
        Out-of-band fraction where motion penalty saturates (maps to 1.0).

    Returns
    -------
    PPGQualityResult
        Contains integer classifications (contact_state, motion_grade, quality_index),
        flags, and useful diagnostics (SNRs, PI, correlation, coherence at fp, etc.).

    Notes
    -----
    - This function is *window-local* and stateless (no hysteresis/baselines). Wrap it with a
      stateful layer in your app for promotion/demotion hysteresis and adaptive PI floors.
    - Uses zero-phase band-pass (sosfiltfilt) inside the window for robust morphology/PSD
      estimation. For hard real-time streaming, swap for causal sosfilt and accept minor phase lag.
    - Coherence is evaluated between band-limited AC signals; we also report coherence at the
      detected fp (if available) as a compact coupling metric.
    """
    flags = 0

    # -------------------- Input validation & coercion --------------------
    try:
        red = _safe_as_float_1d(red)
        ir  = _safe_as_float_1d(ir)
    except Exception:
        flags |= FLAG_INPUT_BAD
        if return_dict:
            return {
                "contact_state": ContactState.OFF_SKIN,
                "motion_grade": MotionGrade.BAD,
                "quality_index": 0,
                "hr_bpm": None,
                "flags": flags | FLAG_NUMERIC_ISSUE,
                "snr_ir_db": -np.inf,
                "snr_red_db": -np.inf,
                "pi_ir_pct": 0.0,
                "pi_red_pct": 0.0,
                "corr_red_ir": 0.0,
                "coh_fp": 0.0,
                "obf": 1.0,
                "fp_hz": None,
                "std_logR": float('inf'),
            }
        
        return PPGQualityResult(
            contact_state=ContactState.OFF_SKIN,
            motion_grade=MotionGrade.BAD,
            quality_index=0,
            hr_bpm=None,
            flags=flags | FLAG_NUMERIC_ISSUE,
            snr_ir_db=-np.inf, snr_red_db=-np.inf,
            pi_ir_pct=0.0, pi_red_pct=0.0,
            corr_red_ir=0.0, coh_fp=0.0, obf=1.0,
            fp_hz=None, std_logR=float('inf'),
        )

    if red.shape != ir.shape or red.ndim != 1:
        flags |= FLAG_INPUT_BAD
        if return_dict:
            return {
                "contact_state": ContactState.OFF_SKIN,
                "motion_grade": MotionGrade.BAD,
                "quality_index": 0,
                "hr_bpm": None,
                "flags": flags,
                "snr_ir_db": -np.inf,
                "snr_red_db": -np.inf,
                "pi_ir_pct": 0.0,
                "pi_red_pct": 0.0,
                "corr_red_ir": 0.0,
                "coh_fp": 0.0,
                "obf": 1.0,
                "fp_hz": None,
                "std_logR": float('inf'),
            }
        
        return PPGQualityResult(
            contact_state=ContactState.OFF_SKIN,
            motion_grade=MotionGrade.BAD,
            quality_index=0,
            hr_bpm=None,
            flags=flags,
            snr_ir_db=-np.inf, snr_red_db=-np.inf,
            pi_ir_pct=0.0, pi_red_pct=0.0,
            corr_red_ir=0.0, coh_fp=0.0, obf=1.0,
            fp_hz=None, std_logR=float('inf'),
        )

    n = len(red)
    # Minimum: ~2 seconds or 64 samples—whichever is larger—so Welch/coherence are stable.
    min_len = max(64, int(2 * fs_hz))
    if n < min_len or fs_hz <= 0:
        flags |= FLAG_INPUT_BAD
        return PPGQualityResult(
            contact_state=ContactState.OFF_SKIN,
            motion_grade=MotionGrade.BAD,
            quality_index=0,
            hr_bpm=None,
            flags=flags,
            snr_ir_db=-np.inf, snr_red_db=-np.inf,
            pi_ir_pct=0.0, pi_red_pct=0.0,
            corr_red_ir=0.0, coh_fp=0.0, obf=1.0,
            fp_hz=None, std_logR=float('inf'),
        )

    # -------------------- Clipping detection (use raw space, if available) --------------------
    try:
        frac_low_red,  frac_high_red = _clipping_fraction(red, adc_bits)
        frac_low_ir,   frac_high_ir  = _clipping_fraction(ir,  adc_bits)
    except Exception:
        frac_low_red = frac_high_red = frac_low_ir = frac_high_ir = 0.0
        flags |= FLAG_NUMERIC_ISSUE

    clipping = False
    if frac_high_red > 0.01 or frac_high_ir > 0.01:
        flags |= FLAG_CLIPPING_HIGH
        clipping = True
    if frac_low_red > 0.01 or frac_low_ir > 0.01:
        flags |= FLAG_CLIPPING_LOW
        clipping = True

    # -------------------- DC/AC decomposition & band-pass --------------------
    # DC via mean (robust enough within a short window); AC = raw - DC
    dc_red = float(np.mean(red))
    dc_ir  = float(np.mean(ir))
    ac_red = red - dc_red
    ac_ir  = ir  - dc_ir

    # Band-limit AC to isolate pulsatile content; zero-phase for robust within-window metrics
    try:
        sos = _butter_bandpass_sos(band_lo_hz, band_hi_hz, fs_hz, order=4)
        ac_red_bl = sosfiltfilt(sos, ac_red, axis=0)
        ac_ir_bl  = sosfiltfilt(sos, ac_ir,  axis=0)
    except Exception:
        # Fallback to unfiltered AC if filtering fails (should be rare)
        ac_red_bl = ac_red
        ac_ir_bl  = ac_ir
        flags |= FLAG_NUMERIC_ISSUE

    # Perfusion Index (scale-free amplitude metric, %)
    pi_red = 100.0 * (_rms(ac_red_bl) / (abs(dc_red) + 1e-12))
    pi_ir  = 100.0 * (_rms(ac_ir_bl)  / (abs(dc_ir)  + 1e-12))

    # -------------------- Spectra & SNR (Welch) --------------------
    snr_ir_db, fpeak_ir, f_ir, P_ir = _power_snr_and_peak(
        ac_ir_bl, fs_hz, f_card_min, f_card_max, peak_bw=0.2
    )
    snr_red_db, fpeak_red, f_red, P_red = _power_snr_and_peak(
        ac_red_bl, fs_hz, f_card_min, f_card_max, peak_bw=0.2
    )

    # fp selection: prefer IR (finger tends to have stronger IR pulsation)
    fp = fpeak_ir if fpeak_ir is not None else fpeak_red
    hr_bpm = None if fp is None else float(fp * 60.0)

    # if fp is None or (snr_ir_db < 3.0 and snr_red_db < 3.0):
    if fp is None or (snr_ir_db < snr_pass_db and snr_red_db < snr_pass_db):
        flags |= FLAG_NO_CARDIAC_PEAK

    # -------------------- Channel coupling: correlation and coherence --------------------
    # Pearson correlation of band-passed AC (time domain)
    if np.std(ac_red_bl) > 0 and np.std(ac_ir_bl) > 0:
        corr = float(np.corrcoef(ac_red_bl, ac_ir_bl)[0, 1])
    else:
        corr = 0.0

    # Magnitude-squared coherence across frequencies; we will report value near fp
    try:
        # Use moderate segment length to keep coherence stable
        nperseg = int(max(128, min(n, round(fs_hz))))
        f_coh, coh = coherence(ac_red_bl, ac_ir_bl, fs=fs_hz, nperseg=nperseg, noverlap=nperseg // 2)
        if fp is not None and len(f_coh) > 0:
            # Find nearest frequency bin to fp
            idx_fp = int(np.argmin(np.abs(f_coh - fp)))
            coh_fp = float(np.clip(coh[idx_fp], 0.0, 1.0))
        else:
            coh_fp = 0.0
    except Exception:
        coh_fp = 0.0
        flags |= FLAG_NUMERIC_ISSUE

    # -------------------- R-stability across sub-slices --------------------
    # R = (AC_red/DC_red) / (AC_ir/DC_ir). Compute per sub-slice using RMS(AC) proxies.
    Rs = []
    try:
        slices_red = _split_into_slices(ac_red_bl, 8)
        slices_ir  = _split_into_slices(ac_ir_bl,  8)
        for s_red, s_ir in zip(slices_red, slices_ir):
            ac_r_rms = _rms(s_red)
            ac_i_rms = _rms(s_ir)
            if ac_r_rms <= 0 or ac_i_rms <= 0:
                continue
            r = ((ac_r_rms / (abs(dc_red) + 1e-12)) /
                 (ac_i_rms  / (abs(dc_ir)  + 1e-12)))
            if r > 0:
                Rs.append(r)
        std_logR = float(np.std(np.log(np.asarray(Rs)))) if len(Rs) >= 2 else float("inf")
    except Exception:
        std_logR = float("inf")
        flags |= FLAG_NUMERIC_ISSUE

    # -------------------- Out-of-band fraction (>8 Hz) --------------------
    def _obf(f: np.ndarray, Pxx: np.ndarray) -> float:
        if len(f) == 0 or len(Pxx) == 0:
            return 1.0
        non_dc = f > 0.0
        total = float(np.sum(Pxx[non_dc]))
        if total <= 0.0:
            return 0.0
        high = float(np.sum(Pxx[f > 8.0]))
        return float(np.clip(high / total, 0.0, 1.0))

    obf_ir = _obf(f_ir, P_ir)
    obf_red = _obf(f_red, P_red)
    obf = max(obf_ir, obf_red)  # conservative

    # Ambient dominance heuristic: little high-frequency energy and no cardiac peak
    if (flags & FLAG_NO_CARDIAC_PEAK) and (obf < 0.05):
        flags |= FLAG_AMBIENT_DOMINANT

    # -------------------- Decision ladder --------------------
    # HARD FAILS → OFF-SKIN/BAD immediately
    if clipping or (flags & FLAG_NO_CARDIAC_PEAK):
        # Explain what we can
        if corr < 0.2 or coh_fp < 0.2:
            flags |= FLAG_DECOUPLED_CHANNELS
        if std_logR > std_logR_bad:
            flags |= FLAG_R_UNSTABLE

        if return_dict:
            return {
                "contact_state": int(ContactState.OFF_SKIN),
                "motion_grade": int(MotionGrade.BAD),
                "quality_index": 0,
                "hr_bpm": None if fp is None else hr_bpm,
                "flags": flags,
                "snr_ir_db": float(snr_ir_db),
                "snr_red_db": float(snr_red_db),
                "pi_ir_pct": float(pi_ir),
                "pi_red_pct": float(pi_red),
                "corr_red_ir": float(corr),
                "coh_fp": float(coh_fp),
                "obf": float(obf),
                "fp_hz": None if fp is None else float(fp),
                "std_logR": float(std_logR),
            }

        return PPGQualityResult(
            contact_state=int(ContactState.OFF_SKIN),
            motion_grade=int(MotionGrade.BAD),
            quality_index=0,
            hr_bpm=None if fp is None else hr_bpm,
            flags=flags,
            snr_ir_db=float(snr_ir_db),
            snr_red_db=float(snr_red_db),
            pi_ir_pct=float(pi_ir),
            pi_red_pct=float(pi_red),
            corr_red_ir=float(corr),
            coh_fp=float(coh_fp),
            obf=float(obf),
            fp_hz=None if fp is None else float(fp),
            std_logR=float(std_logR),
        )

    # CONTACT CLASSIFICATION
    snr_pass = (snr_ir_db >= snr_pass_db) or (snr_red_db >= snr_pass_db)
    pi_pass  = (pi_ir >= pi_floor_pct) or (pi_red >= pi_floor_pct)
    coupling_pass = (corr >= corr_pass_min) or (coh_fp >= 0.40)
    on_skin = snr_pass and pi_pass and coupling_pass
    contact_state = ContactState.ON_SKIN if on_skin else ContactState.OFF_SKIN

    # MOTION GRADING (only meaningful when on-skin)
    # Build motion score M in [0,1] from normalized features
    snr_comb = max(snr_ir_db, snr_red_db)

    # Normalize each term to 0..1 (higher → worse), then weight
    m_obf   = float(np.clip(obf / max(1e-6, obf_high_ref), 0.0, 1.0))          # obf=ref → 1
    m_corr  = float(np.clip(1.0 - max(0.0, corr), 0.0, 1.0))                   # low corr → high penalty
    m_coh   = float(np.clip(1.0 - coh_fp, 0.0, 1.0))                            # low coherence → penalty
    m_rstab = float(np.clip(std_logR / max(1e-6, std_logR_bad), 0.0, 1.0))     # >threshold → 1.0
    # SNR penalty: 3 dB → ~1.0, 12 dB → ~0.0
    m_snr   = float(np.clip(1.0 - (snr_comb - 3.0) / (12.0 - 3.0), 0.0, 1.0))

    # Weights (tune on your data; coherence carries extra weight now)
    w_obf, w_corr, w_coh, w_rstab, w_snr = 0.30, 0.20, 0.20, 0.15, 0.15
    M = w_obf * m_obf + w_corr * m_corr + w_coh * m_coh + w_rstab * m_rstab + w_snr * m_snr

    if contact_state == ContactState.OFF_SKIN:
        motion_grade = MotionGrade.BAD
    else:
        if M <= 0.30:
            motion_grade = MotionGrade.GOOD
        elif M <= 0.60:
            motion_grade = MotionGrade.MODERATE
        else:
            motion_grade = MotionGrade.BAD

    # QUALITY INDEX (0..100): blend of SNR, coupling (corr & coherence), (1-OBF), R-stability
    snr_norm   = float(np.clip((snr_comb - 0.0) / 15.0, 0.0, 1.0))   # 0..15 dB → 0..1
    corr_norm  = float(np.clip((corr - 0.0) / 1.0, 0.0, 1.0))
    coh_norm   = float(np.clip(coh_fp, 0.0, 1.0))                    # coherence is already 0..1
    obf_norm   = float(np.clip(1.0 - obf, 0.0, 1.0))
    rstab_norm = float(np.clip(1.0 - (std_logR / max(1e-6, std_logR_bad)), 0.0, 1.0))

    # Weights emphasize coupling and SNR; keep some credit for low OBF and stable R
    q_w = (0.30, 0.25, 0.20, 0.15, 0.10)  # snr, corr, coh, (1-obf), r-stability
    qi = (q_w[0] * snr_norm + q_w[1] * corr_norm + q_w[2] * coh_norm +
          q_w[3] * obf_norm + q_w[4] * rstab_norm)
    quality_index = int(np.clip(round(100.0 * qi), 0, 100))

    # Flags for interpretability (reasons why contact might be OFF or quality low)
    if not on_skin:
        if not snr_pass:
            flags |= FLAG_NO_CARDIAC_PEAK
        if not pi_pass:
            flags |= FLAG_LOW_PERFUSION
        if not coupling_pass:
            flags |= FLAG_DECOUPLED_CHANNELS
    else:
        if corr < 0.35 or coh_fp < 0.35:
            flags |= FLAG_DECOUPLED_CHANNELS
        if std_logR > 0.12:
            flags |= FLAG_R_UNSTABLE
        if min(pi_ir, pi_red) < pi_floor_pct:
            flags |= FLAG_LOW_PERFUSION

    if return_dict:
        return {
            "contact_state": int(contact_state),
            "motion_grade": int(motion_grade),
            "quality_index": quality_index,
            "hr_bpm": None if fp is None else float(fp * 60.0),
            "flags": flags,
            "snr_ir_db": float(snr_ir_db),
            "snr_red_db": float(snr_red_db),
            "pi_ir_pct": float(pi_ir),
            "pi_red_pct": float(pi_red),
            "corr_red_ir": float(corr),
            "coh_fp": float(coh_fp),
            "obf": float(obf),
            "fp_hz": None if fp is None else float(fp),
            "std_logR": float(std_logR),
        }
    
    return PPGQualityResult(
        contact_state=int(contact_state),
        motion_grade=int(motion_grade),
        quality_index=quality_index,
        hr_bpm=None if fp is None else float(fp * 60.0),
        flags=flags,
        snr_ir_db=float(snr_ir_db),
        snr_red_db=float(snr_red_db),
        pi_ir_pct=float(pi_ir),
        pi_red_pct=float(pi_red),
        corr_red_ir=float(corr),
        coh_fp=float(coh_fp),
        obf=float(obf),
        fp_hz=None if fp is None else float(fp),
        std_logR=float(std_logR),
    )
